                    primary_cpc_codes = uc_pub_to_cpc[cited_pub]
                    for cpc_code in primary_cpc_codes:
                        cpc_title = cpc_code_to_title.get(cpc_code, 'Unknown')
                        citing_relationships.append({
                            'citing_assignee': assignee,
                            'cited_uc_patent': cited_pub,
                            'cpc_code': cpc_code,
                            'cpc_title': cpc_title
                        })
        except:
